				$order_table_delivery_zone_column = $this->db->query("SHOW COLUMNS FROM " . DB_PREFIX . "order LIKE 'delivery_zone_id'");
				if ($order_table_delivery_zone_column->num_rows == 0) {
                    $this->db->query("ALTER TABLE `" . DB_PREFIX . "order` ADD COLUMN delivery_zone_id INT(11) NULL AFTER `shipping_zone_id`");
                    $this->db->query("ALTER TABLE `" . DB_PREFIX . "order` ADD CONSTRAINT `fk_delivery_zone_id` FOREIGN KEY (`delivery_zone_id`) REFERENCES `" . DB_PREFIX . "delivery_zone` (`delivery_zone_id`) ON DELETE RESTRICT ON UPDATE RESTRICT;");
                }
                
                $order_table_driver_id_column = $this->db->query("SHOW COLUMNS FROM " . DB_PREFIX . "order LIKE 'driver_id'");
                if ($order_table_driver_id_column->num_rows == 0) {
                    $this->db->query("ALTER TABLE " . DB_PREFIX . "order ADD COLUMN driver_id INT(11) NULL AFTER `delivery_zone_id`");
                    $this->db->query("ALTER TABLE `" . DB_PREFIX . "order` ADD CONSTRAINT `fk_driver_id` FOREIGN KEY (`driver_id`) REFERENCES `" . DB_PREFIX . "user` (`user_id`) ON DELETE RESTRICT ON UPDATE CASCADE;");
                }

                // Create delivery_zone table
                $delivery_zone_query = $this->db->query("SHOW TABLES LIKE '" . DB_PREFIX . "delivery_zone'");
                if (!$delivery_zone_query->num_rows) {
                    $this->db->query("
                        CREATE TABLE `" . DB_PREFIX . "delivery_zone` (
                            `delivery_zone_id` INT(11) NOT NULL AUTO_INCREMENT,
                            `name` VARCHAR(255) NOT NULL,
                            `user_id` INT(11) NOT NULL,
                            PRIMARY KEY (`delivery_zone_id`)
                        ) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci
                    ");
                }

                // Add delivery_zone_id column to address table
                $customer_query = $this->db->query("SHOW COLUMNS FROM `" . DB_PREFIX . "address` LIKE 'delivery_zone_id'");
                if ($customer_query->num_rows == 0) {
                    $this->db->query("ALTER TABLE `" . DB_PREFIX . "address` ADD `delivery_zone_id` INT(11) NOT NULL AFTER `zone_id`");
                    $this->db->query("ALTER TABLE `" . DB_PREFIX . "address` ADD CONSTRAINT `fk_delivery_zone_id` FOREIGN KEY (`delivery_zone_id`) REFERENCES `" . DB_PREFIX . "address` (`delivery_zone_id`) ON DELETE CASCADE ON UPDATE CASCADE");
                }

                // Add Photo Of Delivery (POD) table
                if (!$this->db->query("SHOW TABLES LIKE '" . DB_PREFIX . "order_pod'")->num_rows) {
                    $this->db->query("
                        CREATE TABLE `" . DB_PREFIX . "order_pod` (
                            `order_pod_id` INT(11) NOT NULL AUTO_INCREMENT,
                            `order_id` INT(11) NOT NULL,
                            `image` VARCHAR(255) NOT NULL,
                            PRIMARY KEY (`order_pod_id`)
                        ) ENGINE=InnoDB DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci
                    ");
                    $this->db->query("ALTER TABLE `" . DB_PREFIX . "order_pod` ADD INDEX `idx_order_id` (`order_id`)");
                }

                // Add created_at column to order_pod table
                if (!$this->db->query("SHOW COLUMNS FROM `" . DB_PREFIX . "order_pod` LIKE 'created_at'")->num_rows) {
                    $this->db->query("ALTER TABLE `" . DB_PREFIX . "order_pod` ADD `created_at` TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP AFTER `image`");
                }

