                public function createPod($data) {
		            $this->db->query("INSERT INTO `" . DB_PREFIX . "order_pod` (`order_id`, `image`) VALUES ('" . (int)$data['order_id'] . "', '" . $this->db->escape($data['image']) . "')");
                }

                public function getPod($order_id) {
		            return $this->db->query("SELECT * FROM `" . DB_PREFIX . "order_pod` WHERE order_id = '" . (int)$order_id . "'")->rows;
                }
